23	    _style.min_height = (int)(_style.min_height * scale);
24	    _style.max_width = (int)(_style.max_width * scale);
25	    _style.max_height = (int)(_style.max_height * scale);
26	    _style.border = (int)(_style.border * scale);
27	    _style.margin_x = (int)(_style.margin_x * scale);
