29	    _style.spacing = (int)(_style.spacing * scale);
30	    _style.candidate_spacing = (int)(_style.candidate_spacing * scale);
31	    _style.hilite_spacing = (int)(_style.hilite_spacing * scale);
32	    _style.hilite_padding_x = (int)(_style.hilite_padding_x * scale);
33	    _style.hilite_padding_y = (int)(_style.hilite_padding_y * scale);
34	    _style.round_corner = (int)(_style.round_corner * scale);
35	    _style.round_corner_ex = (int)(_style.round_corner_ex * scale);
36	    _style.shadow_radius = (int)(_style.shadow_radius * scale);
37	    _style.shadow_offset_x = (int)(_style.shadow_offset_x * scale);
38	    _style.shadow_offset_y = (int)(_style.shadow_offset_y * scale);
39	  }
40	  real_margin_x = ((abs(_style.margin_x) > _style.hilite_padding_x)
41	                       ? abs(_style.margin_x)
42	                       : _style.hilite_padding_x);
43	  real_margin_y = ((abs(_style.margin_y) > _style.hilite_padding_y)
44	                       ? abs(_style.margin_y)
45	                       : _style.hilite_padding_y);
46	  offsetX = offsetY = 0;
47	  if (_style.shadow_radius != 0) {
48	    offsetX = abs(_style.shadow_offset_x) + _style.shadow_radius * 2;
49	    offsetY = abs(_style.shadow_offset_y) + _style.shadow_radius * 2;
50	    if ((_style.shadow_offset_x != 0) || (_style.shadow_offset_y != 0)) {
51	      offsetX -= _style.shadow_radius / 2;
52	      offsetY -= _style.shadow_radius / 2;
53	    }
54	  }
