59	GraphicsRoundRectPath::GraphicsRoundRectPath(const CRect rc,
60	                                             int corner,
61	                                             bool roundTopLeft,
62	                                             bool roundTopRight,
63	                                             bool roundBottomRight,
64	                                             bool roundBottomLeft) {
65	  if (!(roundTopLeft || roundTopRight || roundBottomRight || roundBottomLeft) ||
66	      corner <= 0) {
67	    Gdiplus::Rect& rcp =
68	        Gdiplus::Rect(rc.left, rc.top, rc.Width(), rc.Height());
69	    AddRectangle(rcp);
70	  } else {
71	    int cnx = ((corner * 2 <= rc.Width()) ? corner : (rc.Width() / 2));
72	    int cny = ((corner * 2 <= rc.Height()) ? corner : (rc.Height() / 2));
73	    int elWid = 2 * cnx;
74	    int elHei = 2 * cny;
75	    AddArc(rc.left, rc.top, elWid * roundTopLeft, elHei * roundTopLeft, 180,
76	           90);
77	    AddLine(rc.left + cnx * roundTopLeft, rc.top,
78	            rc.right - cnx * roundTopRight, rc.top);
79	
80	    AddArc(rc.right - elWid * roundTopRight, rc.top, elWid * roundTopRight,
81	           elHei * roundTopRight, 270, 90);
82	    AddLine(rc.right, rc.top + cny * roundTopRight, rc.right,
83	            rc.bottom - cny * roundBottomRight);
84	
85	    AddArc(rc.right - elWid * roundBottomRight,
86	           rc.bottom - elHei * roundBottomRight, elWid * roundBottomRight,
87	           elHei * roundBottomRight, 0, 90);
88	    AddLine(rc.right - cnx * roundBottomRight, rc.bottom,
89	            rc.left + cnx * roundBottomLeft, rc.bottom);
90	
91	    AddArc(rc.left, rc.bottom - elHei * roundBottomLeft,
92	           elWid * roundBottomLeft, elHei * roundBottomLeft, 90, 90);
93	    AddLine(rc.left, rc.top + cny * roundTopLeft, rc.left,
94	            rc.bottom - cny * roundBottomLeft);
95	  }
96	}
