98	void GraphicsRoundRectPath::AddRoundRect(int left,
99	                                         int top,
100	                                         int width,
101	                                         int height,
102	                                         int cornerx,
103	                                         int cornery) {
104	  if (cornery > 0 && cornerx > 0) {
105	    int cnx = ((cornerx * 2 <= width) ? cornerx : (width / 2));
106	    int cny = ((cornery * 2 <= height) ? cornery : (height / 2));
107	    int elWid = 2 * cnx;
108	    int elHei = 2 * cny;
109	    AddArc(left, top, elWid, elHei, 180, 90);
110	    AddLine(left + cnx, top, left + width - cnx, top);
111	
112	    AddArc(left + width - elWid, top, elWid, elHei, 270, 90);
113	    AddLine(left + width, top + cny, left + width, top + height - cny);
114	
115	    AddArc(left + width - elWid, top + height - elHei, elWid, elHei, 0, 90);
116	    AddLine(left + width - cnx, top + height, left + cnx, top + height);
117	
118	    AddArc(left, top + height - elHei, elWid, elHei, 90, 90);
119	    AddLine(left, top + cny, left, top + height - cny);
120	  } else {
121	    Gdiplus::Rect& rc = Gdiplus::Rect(left, top, width, height);
122	    AddRectangle(rc);
123	  }
