14	void weasel::StandardLayout::GetTextSizeDW(
15	    const std::wstring& text,
16	    size_t nCount,
17	    ComPtr<IDWriteTextFormat1>& pTextFormat,
18	    PDWR pDWR,
19	    LPSIZE lpSize) const {
20	  D2D1_SIZE_F sz;
21	  HRESULT hr = S_OK;
22	
23	  if (pTextFormat == NULL) {
24	    lpSize->cx = 0;
25	    lpSize->cy = 0;
26	    return;
27	  }
28	  // 创建文本布局
29	  if (_style.layout_type == UIStyle::LAYOUT_VERTICAL_TEXT)
30	    HR(pDWR->CreateTextLayout(text.c_str(), (int)nCount, pTextFormat.Get(),
31	                              0.0f, (float)_style.max_height));
32	  else
33	    HR(pDWR->CreateTextLayout(text.c_str(), (int)nCount, pTextFormat.Get(),
34	                              (float)_style.max_width, 0));
35	
36	  if (_style.layout_type == UIStyle::LAYOUT_VERTICAL_TEXT) {
37	    DWRITE_FLOW_DIRECTION flow = _style.vertical_text_left_to_right
38	                                     ? DWRITE_FLOW_DIRECTION_LEFT_TO_RIGHT
39	                                     : DWRITE_FLOW_DIRECTION_RIGHT_TO_LEFT;
40	    HR(pDWR->SetLayoutReadingDirection(DWRITE_READING_DIRECTION_TOP_TO_BOTTOM));
41	    HR(pDWR->SetLayoutFlowDirection(flow));
42	  }
43	  // 获取文本尺寸
44	  DWRITE_TEXT_METRICS textMetrics;
45	  HR(pDWR->GetLayoutMetrics(&textMetrics));
46	  sz = D2D1::SizeF(ceil(textMetrics.widthIncludingTrailingWhitespace),
47	                   ceil(textMetrics.height));
48	
49	  lpSize->cx = (int)sz.width;
50	  lpSize->cy = (int)sz.height;
51	
52	  if (_style.layout_type != UIStyle::LAYOUT_VERTICAL_TEXT) {
53	    auto max_width = _style.max_width == 0
54	                         ? textMetrics.widthIncludingTrailingWhitespace
55	                         : _style.max_width;
56	    HR(pDWR->CreateTextLayout(text.c_str(), (int)nCount, pTextFormat.Get(),
57	                              max_width, textMetrics.height));
58	  } else {
59	    auto max_height =
60	        _style.max_height == 0 ? textMetrics.height : _style.max_height;
61	    HR(pDWR->CreateTextLayout(text.c_str(), (int)nCount, pTextFormat.Get(),
62	                              textMetrics.widthIncludingTrailingWhitespace,
63	                              max_height));
64	  }
65	
66	  if (_style.layout_type == UIStyle::LAYOUT_VERTICAL_TEXT) {
67	    HR(pDWR->SetLayoutReadingDirection(DWRITE_READING_DIRECTION_TOP_TO_BOTTOM));
68	    HR(pDWR->SetLayoutFlowDirection(DWRITE_FLOW_DIRECTION_RIGHT_TO_LEFT));
69	  }
70	  DWRITE_OVERHANG_METRICS overhangMetrics;
71	  HR(pDWR->GetLayoutOverhangMetrics(&overhangMetrics));
72	  {
73	    if (overhangMetrics.left > 0)
74	      lpSize->cx += (LONG)(overhangMetrics.left + 1);
75	    if (overhangMetrics.right > 0)
76	      lpSize->cx += (LONG)(overhangMetrics.right + 1);
77	    if (overhangMetrics.top > 0)
78	      lpSize->cy += (LONG)(overhangMetrics.top + 1);
79	    if (overhangMetrics.bottom > 0)
80	      lpSize->cy += (LONG)(overhangMetrics.bottom + 1);
81	  }
82	}
83	
84	CSize StandardLayout::GetPreeditSize(CDCHandle dc,
85	                                     const weasel::Text& text,
86	                                     ComPtr<IDWriteTextFormat1> pTextFormat,
87	                                     PDWR pDWR) {
88	  const std::wstring& preedit = text.str;
89	  const std::vector<weasel::TextAttribute>& attrs = text.attributes;
90	  CSize size(0, 0);
91	  if (!preedit.empty()) {
92	    weasel::TextRange range;
93	    for (size_t j = 0; j < attrs.size(); ++j)
94	      if (attrs[j].type == weasel::HIGHLIGHTED)
95	        _range = attrs[j].range;
96	    if (_range.start < _range.end) {
97	      std::wstring before_str = preedit.substr(0, _range.start);
98	      std::wstring hilited_str = preedit.substr(_range.start, _range.end);
99	      std::wstring after_str = preedit.substr(_range.end);
100	      GetTextSizeDW(before_str, before_str.length(), pTextFormat, pDWR,
101	                    &_beforesz);
102	      GetTextSizeDW(hilited_str, hilited_str.length(), pTextFormat, pDWR,
103	                    &_hilitedsz);
104	      GetTextSizeDW(after_str, after_str.length(), pTextFormat, pDWR,
105	                    &_aftersz);
106	      auto width_max = 0, height_max = 0;
107	      if (_style.layout_type == UIStyle::LAYOUT_VERTICAL_TEXT) {
108	        width_max = max(width_max, _beforesz.cx);
109	        width_max = max(width_max, _hilitedsz.cx);
110	        width_max = max(width_max, _aftersz.cx);
111	        height_max += _beforesz.cy + (_beforesz.cy > 0) * _style.hilite_spacing;
112	        height_max +=
113	            _hilitedsz.cy + (_hilitedsz.cy > 0) * _style.hilite_spacing;
114	        height_max += _aftersz.cy;
115	      } else {
116	        height_max = max(height_max, _beforesz.cy);
117	        height_max = max(height_max, _hilitedsz.cy);
118	        height_max = max(height_max, _aftersz.cy);
119	        width_max += _beforesz.cx + (_beforesz.cx > 0) * _style.hilite_spacing;
120	        width_max +=
121	            _hilitedsz.cx + (_hilitedsz.cx > 0) * _style.hilite_spacing;
122	        width_max += _aftersz.cx;
123	      }
124	      size.cx = width_max;
125	      size.cy = height_max;
126	    } else
127	      GetTextSizeDW(preedit, preedit.length(), pTextFormat, pDWR, &size);
128	  }
129	  return size;
130	}
