132	// check if a candidate back path over _bgRect path
133	bool weasel::StandardLayout::_IsHighlightOverCandidateWindow(CRect& rc,
134	                                                             CDCHandle& dc) {
135	  GraphicsRoundRectPath bgPath(_bgRect, _style.round_corner_ex);
136	  GraphicsRoundRectPath hlPath(rc, _style.round_corner);
137	
138	  Gdiplus::Region bgRegion(&bgPath);
139	  Gdiplus::Region hlRegion(&hlPath);
140	  Gdiplus::Region* tmpRegion = hlRegion.Clone();
141	
142	  if (!tmpRegion)
143	    return false;
144	  tmpRegion->Xor(&bgRegion);
145	  tmpRegion->Exclude(&bgRegion);
146	
147	  Gdiplus::Graphics g(dc);
148	  bool res = !tmpRegion->IsEmpty(&g);
149	  delete tmpRegion;
150	  tmpRegion = NULL;
151	  return res;
152	}
