154	// prepare Hemispherical rounding info
155	void weasel::StandardLayout::_PrepareRoundInfo(CDCHandle& dc) {
156	  const int tmp[5] = {UIStyle::LAYOUT_VERTICAL, UIStyle::LAYOUT_HORIZONTAL,
157	                      UIStyle::LAYOUT_VERTICAL_TEXT, UIStyle::LAYOUT_VERTICAL,
158	                      UIStyle::LAYOUT_HORIZONTAL};
159	  int layout_type = tmp[_style.layout_type];
160	  bool textHemispherical = false, cand0Hemispherical = false;
161	  if (!_style.inline_preedit) {
162	    CRect textRect(_preeditRect);
163	    textRect.InflateRect(_style.hilite_padding_x, _style.hilite_padding_y);
164	    textHemispherical = _IsHighlightOverCandidateWindow(textRect, dc);
165	    const bool hilite_rd_info[3][2][4] = {
166	        // vertical
167	        {{textHemispherical, textHemispherical && (!candidates_count), false,
168	          false},
169	         {true, true, true, true}},
170	        // horizontal
171	        {{textHemispherical, textHemispherical && (!candidates_count), false,
172	          false},
173	         {true, true, true, true}},
174	        // vertical text
175	        {{textHemispherical && (!candidates_count), false, textHemispherical,
176	          false},
177	         {true, true, true, true}}};
178	
179	    _textRoundInfo.IsTopLeftNeedToRound =
180	        hilite_rd_info[layout_type][!textHemispherical][0];
181	    _textRoundInfo.IsBottomLeftNeedToRound =
182	        hilite_rd_info[layout_type][!textHemispherical][1];
183	    _textRoundInfo.IsTopRightNeedToRound =
184	        hilite_rd_info[layout_type][!textHemispherical][2];
185	    _textRoundInfo.IsBottomRightNeedToRound =
186	        hilite_rd_info[layout_type][!textHemispherical][3];
187	    _textRoundInfo.Hemispherical = textHemispherical;
188	    if (_style.vertical_text_left_to_right &&
189	        _style.layout_type == UIStyle::LAYOUT_VERTICAL_TEXT) {
190	      std::swap(_textRoundInfo.IsTopLeftNeedToRound,
191	                _textRoundInfo.IsTopRightNeedToRound);
192	    }
193	  }
194	
195	  if (candidates_count) {
196	    CRect cand0Rect(_candidateRects[0]);
197	    cand0Rect.InflateRect(_style.hilite_padding_x, _style.hilite_padding_y);
198	    cand0Hemispherical = _IsHighlightOverCandidateWindow(cand0Rect, dc);
199	    if (textHemispherical || cand0Hemispherical) {
200	      // if (current_hemispherical_dome_status) _textRoundInfo.Hemispherical =
201	      // true;
202	      //  level 0: m_style.layout_type == UIStyle::LAYOUT_HORIZONTAL
203	      //  level 1: m_style.inline_preedit
204	      //  level 2: BackType
205	      //  level 3: IsTopLeftNeedToRound, IsBottomLeftNeedToRound,
206	      //  IsTopRightNeedToRound, IsBottomRightNeedToRound
207	      const static bool is_to_round_corner[3][2][5][4] = {
208	          // LAYOUT_VERTICAL
209	          {// not inline_preedit
210	           {
211	               {false, false, false, false},  // FIRST_CAND
212	               {false, false, false, false},  // MID_CAND
213	               {false, true, false, true},    // LAST_CAND
214	               {false, true, false, true},    // ONLY_CAND
215	           },
216	           // inline_preedit
217	           {
218	               {true, false, true, false},    // FIRST_CAND
219	               {false, false, false, false},  // MID_CAND
220	               {false, true, false, true},    // LAST_CAND
221	               {true, true, true, true},      // ONLY_CAND
222	           }},
223	          // LAYOUT_HORIZONTAL
224	          {// not inline_preedit
225	           {
226	               {false, true, false, false},   // FIRST_CAND
227	               {false, false, false, false},  // MID_CAND
228	               {false, false, false, true},   // LAST_CAND
229	               {false, true, false, true},    // ONLY_CAND
230	           },
231	           // inline_preedit
232	           {
233	               {true, true, false, false},    // FIRST_CAND
234	               {false, false, false, false},  // MID_CAND
235	               {false, false, true, true},    // LAST_CAND
236	               {true, true, true, true},      // ONLY_CAND
237	           }},
238	          // LAYOUT_VERTICAL_TEXT
239	          {// not inline_preedit
240	           {
241	               {false, false, false, false},  // FIRST_CAND
242	               {false, false, false, false},  // MID_CAND
243	               {true, true, false, false},    // LAST_CAND
244	               {false, false, true, true},    // ONLY_CAND
245	           },
246	           // inline_preedit
247	           {
248	               {false, false, true, true},    // FIRST_CAND
249	               {false, false, false, false},  // MID_CAND
250	               {true, true, false, false},    // LAST_CAND
251	               {true, true, true, true},      // ONLY_CAND
252	           }},
253	      };
254	      for (auto i = 0; i < candidates_count; i++) {
255	        CRect hilite_rect(_candidateRects[i]);
256	        hilite_rect.InflateRect(_style.hilite_padding_x,
257	                                _style.hilite_padding_y);
258	        bool current_hemispherical_dome_status =
259	            _IsHighlightOverCandidateWindow(hilite_rect, dc);
260	        int type = 0;               // default FIRST_CAND
261	        if (candidates_count == 1)  // ONLY_CAND
262	          type = 3;
263	        else if (i != 0 && i != candidates_count - 1)  // MID_CAND
264	          type = 1;
265	        else if (i == candidates_count - 1)  // LAST_CAND
266	          type = 2;
267	        _roundInfo[i].IsTopLeftNeedToRound =
268	            is_to_round_corner[layout_type][_style.inline_preedit][type][0];
269	        _roundInfo[i].IsBottomLeftNeedToRound =
270	            is_to_round_corner[layout_type][_style.inline_preedit][type][1];
271	        _roundInfo[i].IsTopRightNeedToRound =
272	            is_to_round_corner[layout_type][_style.inline_preedit][type][2];
273	        _roundInfo[i].IsBottomRightNeedToRound =
274	            is_to_round_corner[layout_type][_style.inline_preedit][type][3];
275	        _roundInfo[i].Hemispherical = current_hemispherical_dome_status;
276	      }
277	      // fix round info for vetical text layout when vertical_text_left_to_right
278	      // is set
279	      if (_style.layout_type == UIStyle::LAYOUT_VERTICAL_TEXT &&
280	          _style.vertical_text_left_to_right) {
281	        if (_style.inline_preedit) {
282	          if (candidates_count > 1) {
283	            _roundInfo[candidates_count - 1].IsTopLeftNeedToRound =
284	                !_roundInfo[candidates_count - 1].IsTopLeftNeedToRound;
285	            _roundInfo[candidates_count - 1].IsTopRightNeedToRound =
286	                !_roundInfo[candidates_count - 1].IsTopRightNeedToRound;
287	            _roundInfo[candidates_count - 1].IsBottomLeftNeedToRound =
288	                !_roundInfo[candidates_count - 1].IsBottomLeftNeedToRound;
289	            _roundInfo[candidates_count - 1].IsBottomRightNeedToRound =
290	                !_roundInfo[candidates_count - 1].IsBottomRightNeedToRound;
291	            _roundInfo[0].IsTopLeftNeedToRound =
292	                !_roundInfo[0].IsTopLeftNeedToRound;
293	            _roundInfo[0].IsTopRightNeedToRound =
294	                !_roundInfo[0].IsTopRightNeedToRound;
295	            _roundInfo[0].IsBottomLeftNeedToRound =
296	                !_roundInfo[0].IsBottomLeftNeedToRound;
297	            _roundInfo[0].IsBottomRightNeedToRound =
298	                !_roundInfo[0].IsBottomRightNeedToRound;
299	          }
300	        } else {
301	          if (candidates_count > 1) {
302	            _roundInfo[candidates_count - 1].IsTopLeftNeedToRound =
303	                !_roundInfo[candidates_count - 1].IsTopLeftNeedToRound;
304	            _roundInfo[candidates_count - 1].IsTopRightNeedToRound =
305	                !_roundInfo[candidates_count - 1].IsTopRightNeedToRound;
306	            _roundInfo[candidates_count - 1].IsBottomLeftNeedToRound =
307	                !_roundInfo[candidates_count - 1].IsBottomLeftNeedToRound;
308	            _roundInfo[candidates_count - 1].IsBottomRightNeedToRound =
309	                !_roundInfo[candidates_count - 1].IsBottomRightNeedToRound;
310	          }
311	        }
312	      }
313	    }
314	  }
315	}
316	
317	void StandardLayout::UpdateStatusIconLayout(int* width, int* height) {
318	  // rule 1. status icon is middle-aligned with preedit text or auxiliary text,
319	  // whichever comes first rule 2. there is a spacing between preedit/aux text
320	  // and the status icon rule 3. status icon is right aligned in WeaselPanel,
321	  // when [margin_x + width(preedit/aux) + spacing + width(icon) + margin_x] <
322	  // style.min_width
323	  if (ShouldDisplayStatusIcon()) {
324	    if (_style.layout_type == UIStyle::LAYOUT_VERTICAL_TEXT) {
325	      int top = 0, middle = 0;
326	      if (!_preeditRect.IsRectNull()) {
327	        top = _preeditRect.bottom + _style.spacing;
328	        middle = (_preeditRect.left + _preeditRect.right) / 2;
329	      } else if (!_auxiliaryRect.IsRectNull()) {
330	        top = _auxiliaryRect.bottom + _style.spacing;
331	        middle = (_auxiliaryRect.left + _auxiliaryRect.right) / 2;
332	      }
333	      if (top && middle) {
334	        int bottom_alignment = *height - real_margin_y - STATUS_ICON_SIZE;
335	        if (top > bottom_alignment) {
336	          *height = top + STATUS_ICON_SIZE + real_margin_y;
337	        } else {
338	          top = bottom_alignment;
339	        }
340	        _statusIconRect.SetRect(middle - STATUS_ICON_SIZE / 2 + 1, top,
341	                                middle + STATUS_ICON_SIZE,
342	                                top + STATUS_ICON_SIZE / 2 + 1);
343	      } else {
344	        _statusIconRect.SetRect(0, 0, STATUS_ICON_SIZE, STATUS_ICON_SIZE);
345	        _statusIconRect.OffsetRect(offsetX, offsetY);
346	        *width = STATUS_ICON_SIZE;
347	        *height =
348	            (_style.vertical_text_with_wrap ? offsetY : 0) + STATUS_ICON_SIZE;
349	      }
350	    } else {
351	      int left = 0, middle = 0;
352	      if (!_preeditRect.IsRectNull()) {
353	        left = _preeditRect.right + _style.spacing;
354	        middle = (_preeditRect.top + _preeditRect.bottom) / 2;
355	      } else if (!_auxiliaryRect.IsRectNull()) {
356	        left = _auxiliaryRect.right + _style.spacing;
357	        middle = (_auxiliaryRect.top + _auxiliaryRect.bottom) / 2;
358	      }
359	      if (left && middle) {
360	        int right_alignment = *width - real_margin_x - STATUS_ICON_SIZE;
361	        if (left > right_alignment) {
362	          *width = left + STATUS_ICON_SIZE + real_margin_x;
363	        } else {
364	          left = right_alignment;
365	        }
366	        _statusIconRect.SetRect(left, middle - STATUS_ICON_SIZE / 2 + 1,
367	                                left + STATUS_ICON_SIZE,
368	                                middle + STATUS_ICON_SIZE / 2 + 1);
369	      } else {
370	        _statusIconRect.SetRect(0, 0, STATUS_ICON_SIZE, STATUS_ICON_SIZE);
371	        _statusIconRect.OffsetRect(offsetX, offsetY);
372	        *width = *height = STATUS_ICON_SIZE;
373	      }
374	    }
375	  }
376	  if (IS_FULLSCREENLAYOUT(_style))
377	    _statusIconRect.OffsetRect(-_style.border, -_style.border);
378	}
379	
380	bool StandardLayout::IsInlinePreedit() const {
381	  return _style.inline_preedit &&
382	         (_style.client_caps & weasel::INLINE_PREEDIT_CAPABLE) != 0 &&
383	         _style.layout_type != UIStyle::LAYOUT_VERTICAL_FULLSCREEN &&
384	         _style.layout_type != UIStyle::LAYOUT_HORIZONTAL_FULLSCREEN;
385	}
386	
387	bool StandardLayout::ShouldDisplayStatusIcon() const {
388	  // rule 1. emphasis ascii mode
389	  // rule 2. show status icon when switching mode
390	  // rule 3. always show status icon with tips
391	  // rule 4. rule 3 excluding tips FullScreenLayout with strings
392	  return ((_status.ascii_mode && !_style.inline_preedit) ||
393	          !_status.composing || !_context.aux.empty()) &&
394	         !((_style.layout_type == UIStyle::LAYOUT_HORIZONTAL_FULLSCREEN ||
395	            _style.layout_type == UIStyle::LAYOUT_VERTICAL_FULLSCREEN) &&
396	           !_context.aux.empty());
397	}
