1	#include "stdafx.h"
2	#include "HorizontalLayout.h"
3	
4	using namespace weasel;
5	
6	void HorizontalLayout::DoLayout(CDCHandle dc, PDWR pDWR) {
7	  CSize size;
8	  int width = offsetX + real_margin_x, height = offsetY + real_margin_y;
9	  int w = offsetX + real_margin_x;
10	
11	  /* calc mark_text sizes */
12	  if ((_style.hilited_mark_color & 0xff000000)) {
13	    CSize sg;
14	    if (candidates_count) {
15	      if (_style.mark_text.empty())
16	        GetTextSizeDW(L"|", 1, pDWR->pTextFormat, pDWR, &sg);
17	      else
18	        GetTextSizeDW(_style.mark_text, _style.mark_text.length(),
19	                      pDWR->pTextFormat, pDWR, &sg);
20	    }
21	
22	    mark_width = sg.cx;
23	    mark_height = sg.cy;
24	    if (_style.mark_text.empty()) {
25	      mark_width = mark_height / 7;
26	      if (_style.linespacing && _style.baseline)
27	        mark_width =
28	            (int)((float)mark_width / ((float)_style.linespacing / 100.0f));
29	      mark_width = max(mark_width, 6);
30	    }
31	    mark_gap = (_style.mark_text.empty()) ? mark_width
32	                                          : mark_width + _style.hilite_spacing;
33	  }
34	  int base_offset = ((_style.hilited_mark_color & 0xff000000)) ? mark_gap : 0;
35	
36	  // calc page indicator
37	  CSize pgszl, pgszr;
38	  if (!IsInlinePreedit()) {
39	    GetTextSizeDW(pre, pre.length(), pDWR->pPreeditTextFormat, pDWR, &pgszl);
40	    GetTextSizeDW(next, next.length(), pDWR->pPreeditTextFormat, pDWR, &pgszr);
41	  }
42	  bool page_en = (_style.prevpage_color & 0xff000000) &&
43	                 (_style.nextpage_color & 0xff000000);
44	  int pgw = page_en ? (pgszl.cx + pgszr.cx + _style.hilite_spacing +
45	                       _style.hilite_padding_x * 2)
46	                    : 0;
47	  int pgh = page_en ? max(pgszl.cy, pgszr.cy) : 0;
48	
49	  /* Preedit */
50	  if (!IsInlinePreedit() && !_context.preedit.str.empty()) {
51	    size = GetPreeditSize(dc, _context.preedit, pDWR->pPreeditTextFormat, pDWR);
52	    int szx = pgw, szy = max(size.cy, pgh);
53	    // icon size higher then preedit text
54	    int yoffset = (STATUS_ICON_SIZE >= szy && ShouldDisplayStatusIcon())
55	                      ? (STATUS_ICON_SIZE - szy) / 2
56	                      : 0;
57	    _preeditRect.SetRect(w, height + yoffset, w + size.cx,
58	                         height + yoffset + size.cy);
59	    height += szy + 2 * yoffset + _style.spacing;
60	    width = max(width, real_margin_x * 2 + size.cx + szx);
61	    if (ShouldDisplayStatusIcon())
62	      width += STATUS_ICON_SIZE;
63	  }
64	
65	  /* Auxiliary */
66	  if (!_context.aux.str.empty()) {
67	    size = GetPreeditSize(dc, _context.aux, pDWR->pPreeditTextFormat, pDWR);
68	    // icon size higher then auxiliary text
69	    int yoffset = (STATUS_ICON_SIZE >= size.cy && ShouldDisplayStatusIcon())
70	                      ? (STATUS_ICON_SIZE - size.cy) / 2
71	                      : 0;
72	    _auxiliaryRect.SetRect(w, height + yoffset, w + size.cx,
73	                           height + yoffset + size.cy);
74	    height += size.cy + 2 * yoffset + _style.spacing;
75	    width = max(width, real_margin_x * 2 + size.cx);
76	  }
77	
78	  int row_cnt = 0;
79	  int max_width_of_rows = 0;
80	  int height_of_rows[MAX_CANDIDATES_COUNT] = {0};    // height of every row
81	  int row_of_candidate[MAX_CANDIDATES_COUNT] = {0};  // row info of every cand
82	  int mintop_of_rows[MAX_CANDIDATES_COUNT] = {0};
83	  // only when there are candidates
84	  if (candidates_count) {
85	    w = offsetX + real_margin_x;
86	    for (auto i = 0; i < candidates_count && i < MAX_CANDIDATES_COUNT; ++i) {
87	      int current_cand_width = 0;
88	      if (i > 0)
89	        w += _style.candidate_spacing;
90	      if (id == i)
91	        w += base_offset;
92	      /* Label */
93	      std::wstring label =
94	          GetLabelText(labels, i, _style.label_text_format.c_str());
95	      GetTextSizeDW(label, label.length(), pDWR->pLabelTextFormat, pDWR, &size);
96	      _candidateLabelRects[i].SetRect(w, height, w + size.cx * labelFontValid,
97	                                      height + size.cy);
98	      w += size.cx * labelFontValid;
99	      current_cand_width += size.cx * labelFontValid;
100	
101	      /* Text */
102	      w += _style.hilite_spacing;
103	      const std::wstring& text = candidates.at(i).str;
104	      GetTextSizeDW(text, text.length(), pDWR->pTextFormat, pDWR, &size);
105	      _candidateTextRects[i].SetRect(w, height, w + size.cx * textFontValid,
106	                                     height + size.cy);
107	      w += size.cx * textFontValid;
108	      current_cand_width += (size.cx + _style.hilite_spacing) * textFontValid;
109	
110	      /* Comment */
111	      bool cmtFontNotTrans =
112	          (i == id && (_style.hilited_comment_text_color & 0xff000000)) ||
113	          (i != id && (_style.comment_text_color & 0xff000000));
114	      if (!comments.at(i).str.empty() && cmtFontValid && cmtFontNotTrans) {
115	        const std::wstring& comment = comments.at(i).str;
116	        GetTextSizeDW(comment, comment.length(), pDWR->pCommentTextFormat, pDWR,
117	                      &size);
118	        w += _style.hilite_spacing;
119	        _candidateCommentRects[i].SetRect(w, height, w + size.cx * cmtFontValid,
120	                                          height + size.cy);
121	        w += size.cx * cmtFontValid;
