11	  }
12	
13	  CSize size;
14	  int height = offsetY, width = offsetX + real_margin_x;
15	  int h = offsetY + real_margin_y;
16	
17	  if ((_style.hilited_mark_color & 0xff000000)) {
18	    CSize sg;
19	    if (candidates_count) {
20	      if (_style.mark_text.empty())
21	        GetTextSizeDW(L"|", 1, pDWR->pTextFormat, pDWR, &sg);
22	      else
23	        GetTextSizeDW(_style.mark_text, _style.mark_text.length(),
24	                      pDWR->pTextFormat, pDWR, &sg);
25	    }
26	
27	    mark_width = sg.cx;
28	    mark_height = sg.cy;
29	    if (_style.mark_text.empty()) {
30	      mark_height = mark_width / 7;
31	      if (_style.linespacing && _style.baseline)
32	        mark_height =
33	            (int)((float)mark_height / ((float)_style.linespacing / 100.0f));
34	      mark_height = max(mark_height, 6);
35	    }
36	    mark_gap = (_style.mark_text.empty()) ? mark_height
37	                                          : mark_height + _style.hilite_spacing;
38	  }
39	  int base_offset = ((_style.hilited_mark_color & 0xff000000)) ? mark_gap : 0;
40	
41	  // calc page indicator
42	  CSize pgszl, pgszr;
43	  if (!IsInlinePreedit()) {
44	    GetTextSizeDW(pre, pre.length(), pDWR->pPreeditTextFormat, pDWR, &pgszl);
45	    GetTextSizeDW(next, next.length(), pDWR->pPreeditTextFormat, pDWR, &pgszr);
46	  }
47	  bool page_en = (_style.prevpage_color & 0xff000000) &&
48	                 (_style.nextpage_color & 0xff000000);
49	  int pgh = page_en ? pgszl.cy + pgszr.cy + _style.hilite_spacing +
50	                          _style.hilite_padding_y * 2
51	                    : 0;
52	  int pgw = page_en ? max(pgszl.cx, pgszr.cx) : 0;
53	
54	  /* Preedit */
55	  if (!IsInlinePreedit() && !_context.preedit.str.empty()) {
56	    size = GetPreeditSize(dc, _context.preedit, pDWR->pPreeditTextFormat, pDWR);
57	    int szx = max(size.cx, pgw), szy = pgh;
58	    // icon size wider then preedit text
59	    int xoffset = (STATUS_ICON_SIZE >= szx && ShouldDisplayStatusIcon())
60	                      ? (STATUS_ICON_SIZE - szx) / 2
61	                      : 0;
62	    _preeditRect.SetRect(width + xoffset, h, width + xoffset + size.cx,
63	                         h + size.cy);
64	    width += size.cx + xoffset * 2 + _style.spacing;
65	    height = max(height, offsetY + real_margin_y + size.cy + szy);
66	    if (ShouldDisplayStatusIcon())
67	      height += STATUS_ICON_SIZE;
68	  }
69	
70	  /* Auxiliary */
71	  if (!_context.aux.str.empty()) {
72	    size = GetPreeditSize(dc, _context.aux, pDWR->pPreeditTextFormat, pDWR);
73	    // icon size wider then preedit text
74	    int xoffset = (STATUS_ICON_SIZE >= size.cx && ShouldDisplayStatusIcon())
75	                      ? (STATUS_ICON_SIZE - size.cx) / 2
76	                      : 0;
77	    _auxiliaryRect.SetRect(width + xoffset, h, width + xoffset + size.cx,
78	                           h + size.cy);
79	    width += size.cx + xoffset * 2 + _style.spacing;
80	    height = max(height, offsetY + real_margin_y + size.cy);
81	  }
82	  /* Candidates */
83	  int wids[MAX_CANDIDATES_COUNT] = {0};
84	  int w = width;
85	  int max_comment_heihgt = 0, max_content_height = 0;
86	  if (candidates_count) {
87	    for (auto i = 0; i < candidates_count && i < MAX_CANDIDATES_COUNT; ++i) {
88	      int wid = 0;
89	      h = offsetY + real_margin_y + base_offset;
90	      /* Label */
91	      std::wstring label =
92	          GetLabelText(labels, i, _style.label_text_format.c_str());
93	      GetTextSizeDW(label, label.length(), pDWR->pLabelTextFormat, pDWR, &size);
94	      _candidateLabelRects[i].SetRect(w, h, w + size.cx * labelFontValid,
95	                                      h + size.cy);
96	      h += size.cy * labelFontValid;
97	      max_content_height = max(max_content_height, h);
98	      wid = max(wid, size.cx);
99	
100	      /* Text */
101	      h += _style.hilite_spacing * labelFontValid;
102	      const std::wstring& text = candidates.at(i).str;
103	      GetTextSizeDW(text, text.length(), pDWR->pTextFormat, pDWR, &size);
104	      _candidateTextRects[i].SetRect(w, h, w + size.cx * textFontValid,
105	                                     h + size.cy);
106	      h += size.cy * textFontValid;
107	      max_content_height = max(max_content_height, h);
108	      wid = max(wid, size.cx);
109	
110	      /* Comment */
111	      bool cmtFontNotTrans =
112	          (i == id && (_style.hilited_comment_text_color & 0xff000000)) ||
113	          (i != id && (_style.comment_text_color & 0xff000000));
114	      if (!comments.at(i).str.empty() && cmtFontValid && cmtFontNotTrans) {
115	        h += _style.hilite_spacing;
116	        const std::wstring& comment = comments.at(i).str;
117	        GetTextSizeDW(comment, comment.length(), pDWR->pCommentTextFormat, pDWR,
118	                      &size);
119	        _candidateCommentRects[i].SetRect(w, 0, w + size.cx * cmtFontValid,
120	                                          size.cy * cmtFontValid);
121	        h += size.cy * cmtFontValid;
122	        wid = max(wid, size.cx);
123	      } else /* Used for highlighted candidate calculation below */
124	      {
125	        _candidateCommentRects[i].SetRect(w, 0, w, 0);
126	        wid = max(wid, size.cx);
127	      }
128	      wids[i] = wid;
129	      max_comment_heihgt =
130	          max(max_comment_heihgt, _candidateCommentRects[i].Height());
131	      w += wid + _style.candidate_spacing;
132	    }
133	    w -= _style.candidate_spacing;
134	  }
135	
136	  width = max(width, w);
137	  width += real_margin_x;
138	
139	  // reposition candidates
140	  if (candidates_count) {
141	    for (auto i = 0; i < candidates_count && i < MAX_CANDIDATES_COUNT; ++i) {
142	      int ol = 0, ot = 0, oc = 0;
143	      if (_style.align_type == UIStyle::ALIGN_CENTER) {
144	        ol = (wids[i] - _candidateLabelRects[i].Width()) / 2;
145	        ot = (wids[i] - _candidateTextRects[i].Width()) / 2;
146	        oc = (wids[i] - _candidateCommentRects[i].Width()) / 2;
147	      } else if ((_style.align_type == UIStyle::ALIGN_BOTTOM) &&
148	                 _style.vertical_text_left_to_right) {
149	        ol = (wids[i] - _candidateLabelRects[i].Width());
150	        ot = (wids[i] - _candidateTextRects[i].Width());
151	        oc = (wids[i] - _candidateCommentRects[i].Width());
152	      } else if ((_style.align_type == UIStyle::ALIGN_TOP) &&
153	                 (!_style.vertical_text_left_to_right)) {
154	        ol = (wids[i] - _candidateLabelRects[i].Width());
155	        ot = (wids[i] - _candidateTextRects[i].Width());
156	        oc = (wids[i] - _candidateCommentRects[i].Width());
157	      }
158	      // offset rects
159	      _candidateLabelRects[i].OffsetRect(ol, 0);
160	      _candidateTextRects[i].OffsetRect(ot, 0);
161	      _candidateCommentRects[i].OffsetRect(
162	          oc, max_content_height + _style.hilite_spacing);
163	      // define  _candidateRects
164	      _candidateRects[i].left =
165	          min(_candidateLabelRects[i].left, _candidateTextRects[i].left);
166	      _candidateRects[i].left =
167	          min(_candidateRects[i].left, _candidateCommentRects[i].left);
168	      _candidateRects[i].right =
169	          max(_candidateLabelRects[i].right, _candidateTextRects[i].right);
170	      _candidateRects[i].right =
171	          max(_candidateRects[i].right, _candidateCommentRects[i].right);
172	      _candidateRects[i].top = _candidateLabelRects[i].top - base_offset;
173	      _candidateRects[i].bottom =
174	          _candidateCommentRects[i].top + max_comment_heihgt;
175	    }
176	    height = max(height, offsetY + _candidateRects[0].Height() + real_margin_y);
177	    if ((_candidateRects[0].top - real_margin_y + height) >
178	        _candidateRects[0].bottom)
179	      for (auto i = 0; i < candidates_count && i < MAX_CANDIDATES_COUNT; ++i)
180	        _candidateRects[i].bottom =
181	            (_candidateRects[0].top - offsetY - real_margin_y + height);
182	    if (!_style.vertical_text_left_to_right) {
183	      // re position right to left
184	      int base_left;
185	      if ((!IsInlinePreedit() && !_context.preedit.str.empty()))
186	        base_left = _preeditRect.left;
187	      else if (!_context.aux.str.empty())
188	        base_left = _auxiliaryRect.left;
189	      else
190	        base_left = _candidateRects[0].left;
191	      for (int i = candidates_count - 1; i >= 0; i--) {
192	        int offset;
193	        if (i == candidates_count - 1)
194	          offset = base_left - _candidateRects[i].left;
195	        else
196	          offset = _candidateRects[i + 1].right + _style.candidate_spacing -
197	                   _candidateRects[i].left;
198	        _candidateRects[i].OffsetRect(offset, 0);
199	        _candidateLabelRects[i].OffsetRect(offset, 0);
200	        _candidateTextRects[i].OffsetRect(offset, 0);
201	        _candidateCommentRects[i].OffsetRect(offset, 0);
202	      }
203	      if (!IsInlinePreedit() && !_context.preedit.str.empty())
204	        _preeditRect.OffsetRect(
205	            _candidateRects[0].right + _style.spacing - _preeditRect.left, 0);
206	      if (!_context.aux.str.empty())
207	        _auxiliaryRect.OffsetRect(
208	            _candidateRects[0].right + _style.spacing - _auxiliaryRect.left, 0);
209	    }
210	  } else
211	    width -= _style.spacing;
212	
213	  height += real_margin_y;
214	
215	  if (candidates_count) {
216	    width = max(width, _style.min_width);
217	    height = max(height, _style.min_height);
218	  }
219	  UpdateStatusIconLayout(&width, &height);
220	  // candidate rectangle always align to bottom side, margin_y to the bottom
221	  // edge
222	  for (auto i = 0; i < candidates_count && i < MAX_CANDIDATES_COUNT; ++i) {
223	    int bottom = max(_candidateRects[i].bottom, height - real_margin_y);
224	    _candidateCommentRects[i].OffsetRect(
225	        0, bottom - _candidateCommentRects[i].bottom);
226	    _candidateRects[i].bottom = bottom;
227	  }
228	
229	  _highlightRect = _candidateRects[id];
230	  _contentSize.SetSize(width + offsetX, height + offsetY);
231	
232	  // calc page indicator
233	  if (page_en && candidates_count && !_style.inline_preedit) {
234	    int _prey = _contentSize.cy - offsetY - real_margin_y +
235	                _style.hilite_padding_y - pgh;
236	    int _prex = (_preeditRect.left + _preeditRect.right) / 2 - pgszl.cx / 2;
237	    _prePageRect.SetRect(_prex, _prey, _prex + pgszl.cx, _prey + pgszl.cy);
238	    _nextPageRect.SetRect(
239	        _prex, _prePageRect.bottom + _style.hilite_spacing, _prex + pgszr.cx,
240	        _prePageRect.bottom + _style.hilite_spacing + pgszr.cy);
241	    if (ShouldDisplayStatusIcon()) {
242	      _prePageRect.OffsetRect(0, -STATUS_ICON_SIZE);
243	      _nextPageRect.OffsetRect(0, -STATUS_ICON_SIZE);
244	    }
245	  }
246	
247	  _contentRect.SetRect(0, 0, _contentSize.cx, _contentSize.cy);
248	  // background rect prepare for Hemispherical calculation
249	  CopyRect(_bgRect, _contentRect);
250	  _bgRect.DeflateRect(offsetX + 1, offsetY + 1);
251	  // prepare round info
252	  _PrepareRoundInfo(dc);
253	
254	  // truely draw content size calculation
255	  _contentRect.DeflateRect(offsetX, offsetY);
256	}
