258	void VHorizontalLayout::DoLayoutWithWrap(CDCHandle dc, PDWR pDWR) {
259	  CSize size;
260	  int height = offsetY, width = offsetX + real_margin_x;
261	  int h = offsetY + real_margin_y;
262	
263	  if ((_style.hilited_mark_color & 0xff000000)) {
264	    CSize sg;
265	    if (candidates_count) {
266	      if (_style.mark_text.empty())
267	        GetTextSizeDW(L"|", 1, pDWR->pTextFormat, pDWR, &sg);
268	      else
269	        GetTextSizeDW(_style.mark_text, _style.mark_text.length(),
270	                      pDWR->pTextFormat, pDWR, &sg);
271	    }
272	
273	    mark_width = sg.cx;
274	    mark_height = sg.cy;
275	    if (_style.mark_text.empty()) {
276	      mark_height = mark_width / 7;
277	      if (_style.linespacing && _style.baseline)
278	        mark_height =
279	            (int)((float)mark_height / ((float)_style.linespacing / 100.0f));
280	      mark_height = max(mark_height, 6);
281	    }
282	    mark_gap = (_style.mark_text.empty()) ? mark_height
283	                                          : mark_height + _style.hilite_spacing;
284	  }
285	  int base_offset = ((_style.hilited_mark_color & 0xff000000)) ? mark_gap : 0;
286	
287	  // calc page indicator
288	  CSize pgszl, pgszr;
289	  if (!IsInlinePreedit()) {
290	    GetTextSizeDW(pre, pre.length(), pDWR->pPreeditTextFormat, pDWR, &pgszl);
291	    GetTextSizeDW(next, next.length(), pDWR->pPreeditTextFormat, pDWR, &pgszr);
292	  }
293	  bool page_en = (_style.prevpage_color & 0xff000000) &&
294	                 (_style.nextpage_color & 0xff000000);
295	  int pgh = page_en ? pgszl.cy + pgszr.cy + _style.hilite_spacing +
296	                          _style.hilite_padding_y * 2
297	                    : 0;
298	  int pgw = page_en ? max(pgszl.cx, pgszr.cx) : 0;
299	
300	  /* Preedit */
301	  if (!IsInlinePreedit() && !_context.preedit.str.empty()) {
302	    size = GetPreeditSize(dc, _context.preedit, pDWR->pPreeditTextFormat, pDWR);
303	    size_t szx = max(size.cx, pgw), szy = pgh;
304	    // icon size wider then preedit text
305	    int xoffset = ((size_t)STATUS_ICON_SIZE >= szx && ShouldDisplayStatusIcon())
306	                      ? (int)(STATUS_ICON_SIZE - szx) / 2
307	                      : 0;
308	    _preeditRect.SetRect(width + xoffset, h, width + xoffset + size.cx,
309	                         h + size.cy);
310	    width += size.cx + xoffset * 2 + _style.spacing;
311	    height = static_cast<int>(
312	        max((size_t)height, offsetY + real_margin_y + size.cy + szy));
313	    if (ShouldDisplayStatusIcon())
314	      height += STATUS_ICON_SIZE;
315	  }
316	  /* Auxiliary */
317	  if (!_context.aux.str.empty()) {
318	    size = GetPreeditSize(dc, _context.aux, pDWR->pPreeditTextFormat, pDWR);
319	    // icon size wider then auxiliary text
320	    int xoffset = (STATUS_ICON_SIZE >= size.cx && ShouldDisplayStatusIcon())
321	                      ? (STATUS_ICON_SIZE - size.cx) / 2
322	                      : 0;
323	    _auxiliaryRect.SetRect(width + xoffset, h, width + xoffset + size.cx,
324	                           h + size.cy);
325	    width += size.cx + xoffset * 2 + _style.spacing;
326	    height = max(height, offsetY + real_margin_y + size.cy);
327	  }
328	  // candidates
329	  int col_cnt = 0;
330	  int max_height_of_cols = 0;
331	  int width_of_cols[MAX_CANDIDATES_COUNT] = {0};
332	  int col_of_candidate[MAX_CANDIDATES_COUNT] = {0};
333	  int minleft_of_cols[MAX_CANDIDATES_COUNT] = {0};
334	  if (candidates_count) {
335	    h = offsetY + real_margin_y;
336	    for (auto i = 0; i < candidates_count && i < MAX_CANDIDATES_COUNT; i++) {
337	      int current_cand_height = 0;
338	      if (i > 0)
339	        h += _style.candidate_spacing;
340	      if (id == i)
341	        h += base_offset;
342	      /* Label */
343	      std::wstring label =
344	          GetLabelText(labels, i, _style.label_text_format.c_str());
345	      GetTextSizeDW(label, label.length(), pDWR->pLabelTextFormat, pDWR, &size);
346	      _candidateLabelRects[i].SetRect(width, h, width + size.cx,
347	                                      h + size.cy * labelFontValid);
348	      h += size.cy * labelFontValid;
349	      current_cand_height += size.cy * labelFontValid;
350	
351	      /* Text */
352	      h += _style.hilite_spacing;
353	      const std::wstring& text = candidates.at(i).str;
354	      GetTextSizeDW(text, text.length(), pDWR->pTextFormat, pDWR, &size);
355	      _candidateTextRects[i].SetRect(width, h, width + size.cx,
356	                                     h + size.cy * textFontValid);
357	      h += size.cy * textFontValid;
358	      current_cand_height += (size.cy + _style.hilite_spacing) * textFontValid;
359	
360	      /* Comment */
361	      bool cmtFontNotTrans =
362	          (i == id && (_style.hilited_comment_text_color & 0xff000000)) ||
363	          (i != id && (_style.comment_text_color & 0xff000000));
364	      if (!comments.at(i).str.empty() && cmtFontValid && cmtFontNotTrans) {
365	        const std::wstring& comment = comments.at(i).str;
366	        GetTextSizeDW(comment, comment.length(), pDWR->pCommentTextFormat, pDWR,
367	                      &size);
368	        h += _style.hilite_spacing;
369	        _candidateCommentRects[i].SetRect(width, h, width + size.cx,
370	                                          h + size.cy * cmtFontValid);
371	        h += size.cy * cmtFontValid;
372	        current_cand_height += (size.cy + _style.hilite_spacing) * cmtFontValid;
373	      } else
374	        _candidateCommentRects[i].SetRect(width, h, width + size.cx, h);
375	      int base_top = (i == id) ? _candidateLabelRects[i].top - base_offset
376	                               : _candidateLabelRects[i].top;
377	      if (_style.max_height > 0 && (base_top > real_margin_y + offsetY) &&
378	          (_candidateCommentRects[i].bottom - offsetY + real_margin_y >
379	           _style.max_height)) {
380	        max_height_of_cols =
381	            max(max_height_of_cols, _candidateCommentRects[i - 1].bottom);
382	        h = offsetY + real_margin_y + (i == id ? base_offset : 0);
383	        int ofy = h - _candidateLabelRects[i].top;
384	        int ofx = width_of_cols[col_cnt] + _style.candidate_spacing;
385	        _candidateLabelRects[i].OffsetRect(ofx, ofy);
386	        _candidateTextRects[i].OffsetRect(ofx, ofy);
387	        _candidateCommentRects[i].OffsetRect(ofx, ofy);
388	        max_height_of_cols =
389	            max(max_height_of_cols, _candidateCommentRects[i].bottom);
390	        minleft_of_cols[col_cnt] = width;
391	        width += ofx;
392	        h += current_cand_height;
393	        col_cnt++;
394	      } else
395	        max_height_of_cols = max(max_height_of_cols, h);
396	      minleft_of_cols[col_cnt] = width;
397	      width_of_cols[col_cnt] =
398	          max(width_of_cols[col_cnt], _candidateLabelRects[i].Width());
399	      width_of_cols[col_cnt] =
400	          max(width_of_cols[col_cnt], _candidateTextRects[i].Width());
401	      width_of_cols[col_cnt] =
402	          max(width_of_cols[col_cnt], _candidateCommentRects[i].Width());
403	      col_of_candidate[i] = col_cnt;
404	    }
405	
406	    for (auto i = 0; i < candidates_count && i < MAX_CANDIDATES_COUNT; ++i) {
407	      int base_top = (i == id) ? _candidateLabelRects[i].top - base_offset
408	                               : _candidateLabelRects[i].top;
409	      _candidateRects[i].SetRect(minleft_of_cols[col_of_candidate[i]], base_top,
410	                                 minleft_of_cols[col_of_candidate[i]] +
411	                                     width_of_cols[col_of_candidate[i]],
412	                                 _candidateCommentRects[i].bottom);
413	      int ol = 0, ot = 0, oc = 0;
414	      if (_style.align_type == UIStyle::ALIGN_CENTER) {
415	        ol = (width_of_cols[col_of_candidate[i]] -
416	              _candidateLabelRects[i].Width()) /
417	             2;
418	        ot = (width_of_cols[col_of_candidate[i]] -
419	              _candidateTextRects[i].Width()) /
420	             2;
421	        oc = (width_of_cols[col_of_candidate[i]] -
422	              _candidateCommentRects[i].Width()) /
423	             2;
424	      } else if ((_style.align_type == UIStyle::ALIGN_BOTTOM) &&
425	                 _style.vertical_text_left_to_right) {
426	        ol = (width_of_cols[col_of_candidate[i]] -
427	              _candidateLabelRects[i].Width());
428	        ot = (width_of_cols[col_of_candidate[i]] -
429	              _candidateTextRects[i].Width());
430	        oc = (width_of_cols[col_of_candidate[i]] -
431	              _candidateCommentRects[i].Width());
432	      } else if ((_style.align_type == UIStyle::ALIGN_TOP) &&
433	                 (!_style.vertical_text_left_to_right)) {
434	        ol = (width_of_cols[col_of_candidate[i]] -
435	              _candidateLabelRects[i].Width());
436	        ot = (width_of_cols[col_of_candidate[i]] -
437	              _candidateTextRects[i].Width());
438	        oc = (width_of_cols[col_of_candidate[i]] -
439	              _candidateCommentRects[i].Width());
440	      }
441	      _candidateLabelRects[i].OffsetRect(ol, 0);
442	      _candidateTextRects[i].OffsetRect(ot, 0);
443	      _candidateCommentRects[i].OffsetRect(oc, 0);
444	      if ((i < candidates_count - 1 &&
445	           col_of_candidate[i] < col_of_candidate[i + 1]) ||
446	          (i == candidates_count - 1))
447	        _candidateRects[i].bottom = max(height, max_height_of_cols);
448	    }
449	    width = minleft_of_cols[col_cnt] + width_of_cols[col_cnt] - offsetX;
450	    height = max(height, max_height_of_cols);
451	    _highlightRect = _candidateRects[id];
452	  } else
453	    width -= _style.spacing + offsetX;
454	  // reposition if not left to right
455	  int first_cand_of_cols[MAX_CANDIDATES_COUNT] = {0};
456	  int offset_of_cols[MAX_CANDIDATES_COUNT] = {0};
457	  if (!_style.vertical_text_left_to_right) {
458	    // re position right to left
459	    int base_left;
460	    if ((!IsInlinePreedit() && !_context.preedit.str.empty()))
461	      base_left = _preeditRect.left;
462	    else if (!_context.aux.str.empty())
463	      base_left = _auxiliaryRect.left;
464	    else if (candidates_count)
465	      base_left = _candidateRects[0].left;
466	    if (candidates_count) {
467	      // calc offset for each col
468	      for (auto col_t = 0; col_t <= col_cnt; col_t++) {
469	        for (auto i = 0; i < candidates_count; i++) {
470	          if (col_of_candidate[i] == col_t) {
471	            first_cand_of_cols[col_t] = i;
472	            break;
473	          }
474	        }
475	      }
476	      for (auto i = col_cnt; i >= 0; i--) {
477	        int offset;
478	        if (i == col_cnt)
479	          offset = base_left - _candidateRects[first_cand_of_cols[i]].left;
480	        else
481	          offset = _candidateRects[first_cand_of_cols[i + 1]].right +
482	                   _style.candidate_spacing -
483	                   _candidateRects[first_cand_of_cols[i]].left;
484	        offset_of_cols[i] = offset;
485	        _candidateRects[first_cand_of_cols[i]].OffsetRect(offset_of_cols[i], 0);
486	      }
487	      for (auto i = 0; i < candidates_count; i++) {
488	        if (i != first_cand_of_cols[col_of_candidate[i]])
489	          _candidateRects[i].OffsetRect(offset_of_cols[col_of_candidate[i]], 0);
490	        _candidateLabelRects[i].OffsetRect(offset_of_cols[col_of_candidate[i]],
491	                                           0);
492	        _candidateTextRects[i].OffsetRect(offset_of_cols[col_of_candidate[i]],
493	                                          0);
494	        _candidateCommentRects[i].OffsetRect(
495	            offset_of_cols[col_of_candidate[i]], 0);
496	      }
497	      _highlightRect = _candidateRects[id];
498	      if (!IsInlinePreedit() && !_context.preedit.str.empty())
499	        _preeditRect.OffsetRect(
500	            _candidateRects[0].right + _style.spacing - _preeditRect.left, 0);
501	      if (!_context.aux.str.empty())
502	        _auxiliaryRect.OffsetRect(
503	            _candidateRects[0].right + _style.spacing - _auxiliaryRect.left, 0);
504	    }
505	  }
506	
507	  width += real_margin_x;
508	  height += real_margin_y;
509	  if (candidates_count) {
510	    width = max(width, _style.min_width);
511	    height = max(height, _style.min_height);
512	  }
513	  _highlightRect = _candidateRects[id];
514	  UpdateStatusIconLayout(&width, &height);
515	  _contentSize.SetSize(width + 2 * offsetX, height + offsetY);
516	  _contentRect.SetRect(0, 0, _contentSize.cx, _contentSize.cy);
517	
518	  // calc page indicator
519	  if (page_en && candidates_count && !_style.inline_preedit) {
520	    int _prey = _contentSize.cy - offsetY - real_margin_y +
521	                _style.hilite_padding_y - pgh;
