526	        _prePageRect.bottom + _style.hilite_spacing + pgszr.cy);
527	    if (ShouldDisplayStatusIcon()) {
528	      _prePageRect.OffsetRect(0, -STATUS_ICON_SIZE);
529	      _nextPageRect.OffsetRect(0, -STATUS_ICON_SIZE);
530	    }
531	  }
532	
533	  // prepare temp rect _bgRect for roundinfo calculation
534	  CopyRect(_bgRect, _contentRect);
535	  _bgRect.DeflateRect(offsetX + 1, offsetY + 1);
536	  _PrepareRoundInfo(dc);
537	  if (_style.vertical_text_left_to_right) {
538	    for (auto i = 0; i < candidates_count; i++) {
539	      _roundInfo[i].Hemispherical = _roundInfo[0].Hemispherical;
540	      if (_roundInfo[0].Hemispherical) {
541	        if (col_of_candidate[i] == col_cnt) {
