1	#include "stdafx.h"
2	#include "FullScreenLayout.h"
3	
4	using namespace weasel;
5	
6	void weasel::FullScreenLayout::DoLayout(CDCHandle dc, PDWR pDWR) {
7	  if (_context.empty()) {
8	    int width = 0, height = 0;
9	    UpdateStatusIconLayout(&width, &height);
10	    _contentSize.SetSize(width, height);
11	    return;
12	  }
13	
14	  CRect workArea;
15	  HMONITOR hMonitor = MonitorFromRect(mr_inputPos, MONITOR_DEFAULTTONEAREST);
16	  if (hMonitor) {
17	    MONITORINFO info;
18	    info.cbSize = sizeof(MONITORINFO);
19	    if (GetMonitorInfo(hMonitor, &info)) {
20	      workArea = info.rcWork;
21	    }
22	  }
23	
24	  int step = 32;
25	  do {
26	    m_layout->DoLayout(dc, pDWR);
27	  } while (AdjustFontPoint(dc, workArea, step, pDWR));
28	
29	  mark_height = m_layout->mark_height;
30	  mark_width = m_layout->mark_width;
31	  mark_gap = m_layout->mark_gap;
32	  int offsetx = (workArea.Width() - m_layout->GetContentSize().cx) / 2;
33	  int offsety = (workArea.Height() - m_layout->GetContentSize().cy) / 2;
34	  _preeditRect = m_layout->GetPreeditRect();
35	  _preeditRect.OffsetRect(offsetx, offsety);
36	  _auxiliaryRect = m_layout->GetAuxiliaryRect();
37	  _auxiliaryRect.OffsetRect(offsetx, offsety);
38	  _highlightRect = m_layout->GetHighlightRect();
39	  _highlightRect.OffsetRect(offsetx, offsety);
40	
41	  _prePageRect = m_layout->GetPrepageRect();
42	  _prePageRect.OffsetRect(offsetx, offsety);
43	  _nextPageRect = m_layout->GetNextpageRect();
44	  _nextPageRect.OffsetRect(offsetx, offsety);
45	  _range = m_layout->GetPreeditRange();
46	  _beforesz = m_layout->GetBeforeSize();
47	  _hilitedsz = m_layout->GetHilitedSize();
48	  _aftersz = m_layout->GetAfterSize();
49	
50	  for (auto i = 0, n = (int)_context.cinfo.candies.size();
51	       i < n && i < MAX_CANDIDATES_COUNT; ++i) {
52	    _candidateLabelRects[i] = m_layout->GetCandidateLabelRect(i);
53	    _candidateLabelRects[i].OffsetRect(offsetx, offsety);
54	    _candidateTextRects[i] = m_layout->GetCandidateTextRect(i);
55	    _candidateTextRects[i].OffsetRect(offsetx, offsety);
56	    _candidateCommentRects[i] = m_layout->GetCandidateCommentRect(i);
57	    _candidateCommentRects[i].OffsetRect(offsetx, offsety);
58	    _candidateRects[i] = m_layout->GetCandidateRect(i);
59	    _candidateRects[i].OffsetRect(offsetx, offsety);
60	  }
61	  _statusIconRect = m_layout->GetStatusIconRect();
62	
63	  _contentSize.SetSize(workArea.Width(), workArea.Height());
64	  _contentRect.SetRect(0, 0, workArea.Width(), workArea.Height());
65	  _contentRect.DeflateRect(offsetX, offsetY);
66	}
67	
68	bool FullScreenLayout::AdjustFontPoint(CDCHandle dc,
69	                                       const CRect& workArea,
70	                                       int& step,
71	                                       PDWR pDWR) {
72	  if (_context.empty() || step == 0)
73	    return false;
74	  {
75	    int fontPointLabel;
76	    int fontPoint;
77	    int fontPointComment;
78	
79	    if (pDWR->pLabelTextFormat != NULL)
80	      fontPointLabel = (int)(pDWR->pLabelTextFormat->GetFontSize() /
81	                             pDWR->dpiScaleFontPoint);
82	    else
83	      fontPointLabel = 0;
84	    if (pDWR->pTextFormat != NULL)
85	      fontPoint =
86	          (int)(pDWR->pTextFormat->GetFontSize() / pDWR->dpiScaleFontPoint);
87	    else
